import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface VaccinationHistory {
  doseNumber: number;
  date: string;
  vaccine: string;
}

interface VaccinationData {
  vaccinationStatus: {
    dosesReceived: number;
    nextDueDate: string;
    coveragePercentage: number;
  };
  vaccinationHistory: VaccinationHistory[];
}

export default function Widget() {
  const vaccinationData = response.data as VaccinationData;
  const { vaccinationStatus, vaccinationHistory } = vaccinationData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} color="primary">
              Vaccination Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Doses Received: {vaccinationStatus.dosesReceived}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Next Due Date: {vaccinationStatus.nextDueDate}
            </Typography>
            <Typography variant="body2" color="primary">
              Coverage: {vaccinationStatus.coveragePercentage}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: vaccinationHistory.map(h => h.doseNumber),
                  color: '#4CAF50',
                  label: 'Doses',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: vaccinationHistory.map(h => h.date),
                  id: 'dates',
                },
              ]}
              yAxis={[{ id: 'doses' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="dates"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="doses"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {vaccinationHistory.map((history, index) => (
              <Chip
                key={index}
                label={`Dose ${history.doseNumber}: ${history.vaccine}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
